     1	import {
     2	  Injectable,
     3	  ConflictException,
     4	  NotFoundException,
     5	  BadRequestException,
     6	} from '@nestjs/common';
     7	import { InjectRepository } from '@nestjs/typeorm';
     8	import { Repository } from 'typeorm';
     9	import { randomUUID } from 'crypto';
    10	import { CustomProvider } from '../../entities/custom-provider.entity';
    11	import { ProviderService } from '../routing-core/provider.service';
    12	import { RoutingCacheService } from '../routing-core/routing-cache.service';
    13	import { TierAutoAssignService } from '../routing-core/tier-auto-assign.service';
    14	import { CreateCustomProviderDto, UpdateCustomProviderDto } from '../dto/custom-provider.dto';
    15	import { validatePublicUrl } from '../../common/utils/url-validation';
    16	
    17	@Injectable()
    18	export class CustomProviderService {
    19	  constructor(
    20	    @InjectRepository(CustomProvider)
    21	    private readonly repo: Repository<CustomProvider>,
    22	    private readonly providerService: ProviderService,
    23	    private readonly routingCache: RoutingCacheService,
    24	    private readonly autoAssign: TierAutoAssignService,
    25	  ) {}
    26	
    27	  /** Provider key used in UserProvider tables. */
    28	  static providerKey(id: string): string {
    29	    return `custom:${id}`;
    30	  }
    31	
    32	  /** Unique model name for model lookups. */
    33	  static modelKey(id: string, modelName: string): string {
    34	    return `custom:${id}/${modelName}`;
    35	  }
    36	
    37	  /** Strip the custom prefix to get the raw model name for upstream API. */
    38	  static rawModelName(prefixedName: string): string {
    39	    const slash = prefixedName.indexOf('/');
    40	    return slash !== -1 ? prefixedName.substring(slash + 1) : prefixedName;
    41	  }
    42	
    43	  /** Check if a provider key is a custom provider. */
    44	  static isCustom(provider: string): boolean {
    45	    return provider.startsWith('custom:');
    46	  }
    47	
    48	  /** Extract the custom provider UUID from a provider key. */
    49	  static extractId(providerKey: string): string {
    50	    return providerKey.replace('custom:', '');
    51	  }
    52	
    53	  async list(agentId: string): Promise<CustomProvider[]> {
    54	    const cached = this.routingCache.getCustomProviders(agentId);
    55	    if (cached) return cached;
    56	
    57	    const result = await this.repo.find({ where: { agent_id: agentId } });
    58	    this.routingCache.setCustomProviders(agentId, result);
    59	    return result;
    60	  }
    61	
    62	  async create(
    63	    agentId: string,
    64	    userId: string,
    65	    dto: CreateCustomProviderDto,
    66	  ): Promise<CustomProvider> {
    67	    const existing = await this.repo.findOne({
    68	      where: { agent_id: agentId, name: dto.name },
    69	    });
    70	    if (existing) {
    71	      throw new ConflictException(`Custom provider "${dto.name}" already exists for this agent`);
    72	    }
    73	
    74	    try {
    75	      await validatePublicUrl(dto.base_url);
    76	    } catch (err) {
    77	      throw new BadRequestException((err as Error).message);
    78	    }
    79	
    80	    const id = randomUUID();
    81	    const provKey = CustomProviderService.providerKey(id);
    82	
    83	    const cp = Object.assign(new CustomProvider(), {
    84	      id,
    85	      agent_id: agentId,
    86	      user_id: userId,
    87	      name: dto.name,
    88	      base_url: dto.base_url,
    89	      models: dto.models.map((m) => ({
    90	        model_name: m.model_name,
    91	        input_price_per_million_tokens: m.input_price_per_million_tokens,
    92	        output_price_per_million_tokens: m.output_price_per_million_tokens,
    93	        context_window: m.context_window ?? 128000,
    94	      })),
    95	      created_at: new Date().toISOString(),
    96	    });
    97	    await this.repo.insert(cp);
    98	
    99	    // Create UserProvider + trigger tier recalculation
   100	    await this.providerService.upsertProvider(agentId, userId, provKey, dto.apiKey);
   101	
   102	    return cp;
   103	  }
   104	
   105	  async update(
   106	    agentId: string,
   107	    id: string,
   108	    userId: string,
   109	    dto: UpdateCustomProviderDto,
   110	  ): Promise<CustomProvider> {
   111	    const cp = await this.repo.findOne({ where: { id, agent_id: agentId } });
   112	    if (!cp) {
   113	      throw new NotFoundException('Custom provider not found');
   114	    }
   115	
   116	    if (dto.name !== undefined && dto.name !== cp.name) {
   117	      const dup = await this.repo.findOne({
   118	        where: { agent_id: agentId, name: dto.name },
   119	      });
   120	      if (dup) {
   121	        throw new ConflictException(`Custom provider "${dto.name}" already exists for this agent`);
   122	      }
   123	      cp.name = dto.name;
   124	    }
   125	
   126	    if (dto.base_url !== undefined) {
   127	      try {
   128	        await validatePublicUrl(dto.base_url);
   129	      } catch (err) {
   130	        throw new BadRequestException((err as Error).message);
   131	      }
   132	      cp.base_url = dto.base_url;
   133	    }
   134	
   135	    if (dto.models !== undefined) {
   136	      cp.models = dto.models.map((m) => ({
   137	        model_name: m.model_name,
   138	        input_price_per_million_tokens: m.input_price_per_million_tokens,
   139	        output_price_per_million_tokens: m.output_price_per_million_tokens,
   140	        context_window: m.context_window ?? 128000,
   141	      }));
   142	    }
   143	
   144	    // Update API key if explicitly provided
   145	    if ('apiKey' in dto) {
   146	      await this.providerService.upsertProvider(
   147	        agentId,
   148	        userId,
   149	        CustomProviderService.providerKey(id),
   150	        dto.apiKey,
   151	      );
   152	    }
   153	
   154	    // Recalculate tiers when models changed (even without API key change)
   155	    if (dto.models !== undefined && !('apiKey' in dto)) {
   156	      await this.autoAssign.recalculate(agentId);
   157	    }
   158	
   159	    await this.repo.save(cp);
   160	    this.routingCache.invalidateAgent(agentId);
   161	
   162	    return cp;
   163	  }
   164	
   165	  async remove(agentId: string, id: string): Promise<void> {
   166	    const cp = await this.repo.findOne({ where: { id, agent_id: agentId } });
   167	    if (!cp) {
   168	      throw new NotFoundException('Custom provider not found');
   169	    }
   170	
   171	    const provKey = CustomProviderService.providerKey(id);
   172	
   173	    // Remove UserProvider + tier overrides
   174	    try {
   175	      await this.providerService.removeProvider(agentId, provKey);
   176	    } catch {
   177	      // Provider may not exist if creation partially failed
   178	    }
   179	
   180	    // Delete CustomProvider row
   181	    await this.repo.remove(cp);
   182	  }
   183	
   184	  async getById(id: string): Promise<CustomProvider | null> {
   185	    return this.repo.findOne({ where: { id } });
   186	  }
   187	}
