   221	
   222	  // Custom providers use their own dynamic endpoint
   223	  if (lower.startsWith('custom:')) return lower;
   224	
   225	  // Look up via SST alias map — check id and all aliases against endpoints
   226	  const entry = PROVIDER_BY_ID_OR_ALIAS.get(lower);
   227	  if (entry) {
   228	    if (PROVIDER_ENDPOINTS[entry.id]) return entry.id;
   229	    for (const alias of entry.aliases) {
   230	      if (PROVIDER_ENDPOINTS[alias]) return alias;
   231	    }
   232	  }
   233	
   234	  return null;
