   279	        ? `$${Number(exceeded.actual).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
   280	        : Number(exceeded.actual).toLocaleString(undefined, { maximumFractionDigits: 0 });
   281	    const threshFmt =
   282	      exceeded.metricType === 'cost'
   283	        ? `$${Number(exceeded.threshold).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
   284	        : Number(exceeded.threshold).toLocaleString(undefined, { maximumFractionDigits: 0 });
   285	    const dashboardUrl = getDashboardUrl(this.config, agentName, 'limits');
   286	    return `[🦚 Manifest] You hit your ${exceeded.metricType} limit: ${fmt} used, ${threshFmt}/${exceeded.period} allowed. Adjust it here: ${dashboardUrl}`;
