   295	  private detectHeartbeat(scoringMessages: ScorerMessage[]): boolean {
   296	    const lastUser = [...scoringMessages].reverse().find((m) => m.role === 'user');
   297	    if (!lastUser) return false;
   298	    if (typeof lastUser.content === 'string') return lastUser.content.includes('HEARTBEAT_OK');
   299	    if (Array.isArray(lastUser.content)) {
   300	      return (lastUser.content as { type?: string; text?: string }[]).some(
   301	        (p) => p.type === 'text' && typeof p.text === 'string' && p.text.includes('HEARTBEAT_OK'),
   302	      );
   303	    }
   304	    return false;
   305	  }
