// Quick repro for the custom provider model ID stripping issue
// This tests stripModelPrefix behavior for custom providers with slash-containing model IDs

// We need to simulate what happens in provider-client.ts
function stripModelPrefix(model: string, endpointKey: string): string {
  if (endpointKey === 'openrouter') return model;
  const slashIdx = model.indexOf('/');
  return slashIdx > 0 ? model.substring(slashIdx + 1) : model;
}

// Simulate what rawModelName does (from custom-provider.service.ts) 
function rawModelName(prefixedName: string): string {
  const slash = prefixedName.indexOf('/');
  return slash !== -1 ? prefixedName.substring(slash + 1) : prefixedName;
}

// Test case 1: Simple custom provider model (no slashes in upstream name)
const model1 = "custom:cp-1/llama-3.1-70b";
const afterRaw1 = rawModelName(model1);
const afterStrip1 = stripModelPrefix(afterRaw1, 'custom');
console.log("Test 1: Simple model");
console.log("  Input:", model1);
console.log("  After rawModelName:", afterRaw1);
console.log("  After stripModelPrefix:", afterStrip1);
console.log("  Expected: llama-3.1-70b");
console.log("  PASS:", afterStrip1 === "llama-3.1-70b");

// Test case 2: Fireworks Fire Pass model (slashes in upstream name)
