console.log("  After stripModelPrefix:", afterStrip2);
console.log("  Expected: accounts/fireworks/routers/kimi-k2p5-turbo");
console.log("  PASS:", afterStrip2 === "accounts/fireworks/routers/kimi-k2p5-turbo");
